sql:
SELECT name
FROM instructor
WHERE dept_name = 'Computer Science';

SELECT COUNT(course_id) AS course_count
FROM course
WHERE semester = 'Fall' AND year = 2023;

SELECT COUNT(*) AS section_count
FROM section
WHERE semester = 'Fall' AND year = 2023;

SELECT COUNT(*) AS classroom_count
FROM classroom
WHERE building = '1';

SELECT building, capacity
FROM classroom
ORDER BY capacity DESC;

SELECT building
FROM classroom
WHERE classroom_type = 'lab';

SELECT building, COUNT(*) AS total_classrooms
FROM classroom
GROUP BY building;

SELECT course_name 
FROM course 
ORDER BY course_name ASC;

SELECT DISTINCT dept_name
FROM course
WHERE year = 2023;

SELECT COUNT(*) AS accessible_classrooms
  FROM classroom
  WHERE accessibility_features LIKE '%Wheelchair Access%';

SELECT building, room_number, classroom_type
FROM classroom
ORDER BY building, room_number;

SELECT course_name
FROM course
WHERE semester = 'Spring' AND year = 2023;

SELECT capacity
FROM classroom
WHERE building = '1';

SELECT course_name
FROM course
ORDER BY dept_name, course_name;

SELECT dept_name
FROM department
ORDER BY dept_name;

SELECT MAX(capacity) AS max_capacity
FROM classroom
WHERE building = 'Science Hall';
